                     updateFieldValue.data['old_value'] = old_value;
                     updateFieldValue.data['table_id'] = $('#'+table_id).attr('data-id');
                     updateFieldValue.data['config_id'] = config_id;
                     updateFieldValue.data['functionName'] = 'UpdateAmendFieldValueCallBack';
